INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('promotion-d0d1b9a2-moex-00073', 'promotion-d0d1b9a2', 'promotion-d0d1b9a2-moex-112-78566e18', 'sub-promotion-d0d1b9a2-01', NULL, 'single_choice', '依據國際財務報導準則第9號「金融工具」之金融資產，下列敘述何者錯誤？', '["「按攤銷後成本衡量之金融資產」以公允價值加交易成本作為原始入帳金額。出售時之交 易成本應列報為費損", "「透過其他綜合損益按公允價值衡量之債務工具投資」於除列時，應將累計其他綜合損益 重分類至損益", "「按攤銷後成本衡量之金融資產」減損時，估計的預期信用損失為期末備抵損失應有的餘 額，該備抵損失應於資產負債表中列於其他綜合損益項下", "企業只有在管理的金融資產之經營模式改變時，才可以將受影響的金融資產重分類。所有 權益工具均不得重分類"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:03+00:00", "source_pdf_sha1": "3948339ea332", "answer_pdf_sha1": "3f7845caa637", "source_family": "moex-gov-tw", "moex": {"exam_code": "112170", "c": "120", "s": "1003", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "112", "exam_name": "112年公務人員升官等考試、112年關務人員升官等考試、112年交通事業鐵路人員升資考試、112年交通事業港務人員升資考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "會計"}'::jsonb, NULL),
  ('promotion-d0d1b9a2-moex-00074', 'promotion-d0d1b9a2', 'promotion-d0d1b9a2-moex-112-78566e18', 'sub-promotion-d0d1b9a2-01', NULL, 'single_choice', 'X5年底，偉倫公司作為銷售總部的一棟辦公大樓，該大樓土地部分之帳面金額為$60,000,000， 建築物部分之帳面金額為$72,000,000（原始成本$120,000,000，累計折舊$48,000,000），剩餘 耐用年限為12年，估計殘值為0，以直線法提列折舊。銷售總部於X6年3月底搬遷至他處， 原辦公大樓改為出租用途，符合投資性不動產的定義與條件，並以公允價值模式衡量。X6年 3月底土地部分之公允價值為$67,000,000，建築物部分之公允價值為$59,000,000。試作X6年 3月底營業用不動產變更用途時，認列之費損金額為：', '["$0", "$1,500,000", "$4,500,000", "$6,100,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:03+00:00", "source_pdf_sha1": "3948339ea332", "answer_pdf_sha1": "3f7845caa637", "source_family": "moex-gov-tw", "moex": {"exam_code": "112170", "c": "120", "s": "1003", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "112", "exam_name": "112年公務人員升官等考試、112年關務人員升官等考試、112年交通事業鐵路人員升資考試、112年交通事業港務人員升資考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "會計"}'::jsonb, NULL),
  ('promotion-d0d1b9a2-moex-00075', 'promotion-d0d1b9a2', 'promotion-d0d1b9a2-moex-112-78566e18', 'sub-promotion-d0d1b9a2-01', NULL, 'single_choice', 'X1年5月1日昇達公司以現金$767,600，購買榮明公司發行之5年期公司債，面額$800,000， 票面利率6%，每年底付息。昇達公司會計人員將此債務工具投資依據企業管理金融資產之經 營模式及合約現金流量特性，錯誤歸類為按攤銷後成本衡量之金融資產，並以直線法攤銷溢 折價。X1年年底該債券之公允價值為$814,000。試問前述分類錯誤之會計處理，相較於正確 分類為透過損益按公允價值衡量之金融資產，對X1年度保留盈餘之影響為：', '["低估保留盈餘$42,080", "高估保留盈餘$42,080", "低估保留盈餘$46,400", "高估保留盈餘$46,400"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:03+00:00", "source_pdf_sha1": "3948339ea332", "answer_pdf_sha1": "3f7845caa637", "source_family": "moex-gov-tw", "moex": {"exam_code": "112170", "c": "120", "s": "1003", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "112", "exam_name": "112年公務人員升官等考試、112年關務人員升官等考試、112年交通事業鐵路人員升資考試、112年交通事業港務人員升資考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "會計"}'::jsonb, NULL),
  ('promotion-d0d1b9a2-moex-00076', 'promotion-d0d1b9a2', 'promotion-d0d1b9a2-moex-112-78566e18', 'sub-promotion-d0d1b9a2-01', NULL, 'single_choice', 'X3 年初，理想公司承包一項長期建造工程，履約義務係隨時間逐步滿足。工程總價為 $5,600,00，至X3年初為止，累計實際投入之工程成本為$1,200,000，累計請款與收款金額分 別為$950,000與$800,000。理想公司對於該項長期工程之損益無法可靠估計，X3年度續投入 工程成本$920,000，X3 年結束預期很有可能回收之成本總額為$1,900,000，當年度請款及實 際收款金額分別為$900,000及$810,000。試問X3年底理想公司帳上合約資產餘額為：', '["$0", "$50,000", "$240,000", "$270,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:03+00:00", "source_pdf_sha1": "3948339ea332", "answer_pdf_sha1": "3f7845caa637", "source_family": "moex-gov-tw", "moex": {"exam_code": "112170", "c": "120", "s": "1003", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "112", "exam_name": "112年公務人員升官等考試、112年關務人員升官等考試、112年交通事業鐵路人員升資考試、112年交通事業港務人員升資考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "會計"}'::jsonb, NULL),
  ('promotion-d0d1b9a2-moex-00077', 'promotion-d0d1b9a2', 'promotion-d0d1b9a2-moex-112-78566e18', 'sub-promotion-d0d1b9a2-01', NULL, 'single_choice', '東安公司有一辦公大樓，購入成本為$1,600,000。X5 年初，該辦公大樓之帳面金額為 $1,100,000，至X5年底，其帳面金額為$850,000。在報稅上，該辦公大樓之累計折舊在X5年 度增加$400,000。此外，東安公司在X5年認列產品保證負債$60,000。東安公司X5年度的會 計利潤為$3,140,000，假設稅率為維持18%。試問東安公司X5年度之所得稅會計處理，下列 敘述何著正確？', '["借：遞延所得稅負債$27,000", "借：遞延所得稅資產$27,000", "貸：遞延所得稅負債$27,000", "借：遞延所得稅負債$10,800"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:03+00:00", "source_pdf_sha1": "3948339ea332", "answer_pdf_sha1": "3f7845caa637", "source_family": "moex-gov-tw", "moex": {"exam_code": "112170", "c": "120", "s": "1003", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "112", "exam_name": "112年公務人員升官等考試、112年關務人員升官等考試、112年交通事業鐵路人員升資考試、112年交通事業港務人員升資考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "會計"}'::jsonb, NULL),
  ('promotion-d0d1b9a2-moex-00078', 'promotion-d0d1b9a2', 'promotion-d0d1b9a2-moex-112-78566e18', 'sub-promotion-d0d1b9a2-01', NULL, 'single_choice', '新竹石油公司於X1年1月1日花費$1,200,000建立一加油站，使用年限預計為 10年，在使 用年限期滿後，新竹石油公司應進行場地復原工作，以X10年底之物價估計，屆時之復原工 作成本為$120,000。公司對加油站採直線法折舊，估計無殘值，折現率為 10%。又該公司於 X1年底重新估計屆時之復原工作成本為$100,000（以X10年底之物價估計）。下列敘述有幾 項正確？（註：p10,10%=0.385543；p9,10%=0.424098；p8,10%=0.466507）', '["該公司於X1年1月1日應認列不動產、廠房及設備金額$1,238,554", "該公司X1年底的除役負債準備應為$42,410", "該公司X1年的財務成本為$3,855", "該公司X1年底的不動產、廠房及設備淨額為$1,121,639"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:03+00:00", "source_pdf_sha1": "3948339ea332", "answer_pdf_sha1": "3f7845caa637", "source_family": "moex-gov-tw", "moex": {"exam_code": "112170", "c": "120", "s": "1003", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "112", "exam_name": "112年公務人員升官等考試、112年關務人員升官等考試、112年交通事業鐵路人員升資考試、112年交通事業港務人員升資考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "會計"}'::jsonb, NULL),
  ('promotion-d0d1b9a2-moex-00079', 'promotion-d0d1b9a2', 'promotion-d0d1b9a2-moex-112-78566e18', 'sub-promotion-d0d1b9a2-01', NULL, 'single_choice', '中和公司採定期盤存制，其存貨儲存於本地倉庫與另一外地倉庫。於編製 X5 年第一季的期 中報表時，本地倉庫存貨盤點結果為$24,000，但因故無法及時實地盤點外地倉庫之存貨。中 和公司利用過去資訊估計外地倉庫的期末存貨。相關資訊如下（全公司）： X5年1月1日帳載存貨 $40,000 X5年第一季進貨 260,000 X5年第一季銷貨收入 220,000 中和公司進貨中包含3月31日購買的存貨$25,000（起運點交貨，於4月1日運抵本地倉庫）， 但不包含3月29日購買的存貨$23,000（目的地交貨，於4月5日運抵本地倉庫）。該公司過 往設定的合理毛利為銷貨成本的 25%。試問中和公司 3 月 31 日儲存於外地倉庫之期末存貨 估計金額為何？', '["$75,000", "$86,000", "$100,000", "$111,000"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:03+00:00", "source_pdf_sha1": "3948339ea332", "answer_pdf_sha1": "3f7845caa637", "source_family": "moex-gov-tw", "moex": {"exam_code": "112170", "c": "120", "s": "1003", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "112", "exam_name": "112年公務人員升官等考試、112年關務人員升官等考試、112年交通事業鐵路人員升資考試、112年交通事業港務人員升資考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "會計"}'::jsonb, NULL),
  ('promotion-d0d1b9a2-moex-00080', 'promotion-d0d1b9a2', 'promotion-d0d1b9a2-moex-112-78566e18', 'sub-promotion-d0d1b9a2-01', NULL, 'single_choice', '屏東公司具有以下與無形資產相關的支出：', '["公司於X3年初以現金$5,000,000購買一專利權A，法定年限為10年，經濟年限為8年， 無殘值", "公司於X1年初以現金$1,000,000購買一專利權B，法定年限與經濟年限皆為10年，無殘 值。X4年底因技術進步，屏東公司認為專利權B已發生減損，使用價值為$520,000，公允 價值減處分成本為$480,000。 在原始認列後，屏東公司對無形資產的衡量採成本模式。試問屏東公司 X4 年底無形資產的 帳面金額為何？", "$4,230,000", "$4,270,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:03+00:00", "source_pdf_sha1": "3948339ea332", "answer_pdf_sha1": "3f7845caa637", "source_family": "moex-gov-tw", "moex": {"exam_code": "112170", "c": "120", "s": "1003", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "112", "exam_name": "112年公務人員升官等考試、112年關務人員升官等考試、112年交通事業鐵路人員升資考試、112年交通事業港務人員升資考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "會計"}'::jsonb, NULL),
  ('promotion-d0d1b9a2-moex-00081', 'promotion-d0d1b9a2', 'promotion-d0d1b9a2-moex-112-78566e18', 'sub-promotion-d0d1b9a2-01', NULL, 'single_choice', '韋德公司於X3年1月1日向銀行借款$5,000,000，期間5年，利率固定為5%（等於當時之 市場利率），每年底付息。X4 年度因財務吃緊，於 X4 年底支付利息後，韋德公司向銀行提 出債務協商之要求，希望將利率降為 3%。到期日與到期本金均維持不變。銀行於 X4 年 12 月31日同意韋德公司之請求，將貸款利率降為3%，並收取協商手續費$16,000。假定韋德公 司X4年12月31日借款之市場利率為6%。試問此交易事項對韋德公司X4年之影響為： （註：p5%,3=0.863838，p5%,4=0.822702，p6%,3=0.839619，p6%,4=0.792094； P5%,3=2.723248，P5%,4=3.545951，P6%,3=2.673012，P6%,4=3.465106）', '["對淨利無影響", "淨利減少$256,325", "淨利增加$272,325", "淨利增加$384,952"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:03+00:00", "source_pdf_sha1": "3948339ea332", "answer_pdf_sha1": "3f7845caa637", "source_family": "moex-gov-tw", "moex": {"exam_code": "112170", "c": "120", "s": "1003", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "112", "exam_name": "112年公務人員升官等考試、112年關務人員升官等考試、112年交通事業鐵路人員升資考試、112年交通事業港務人員升資考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "會計"}'::jsonb, NULL),
  ('promotion-d0d1b9a2-moex-00082', 'promotion-d0d1b9a2', 'promotion-d0d1b9a2-moex-112-ac2adf20', 'sub-promotion-d0d1b9a2-02', NULL, 'essay', '依中央政府普通公務單位會計制度之一致規定，甲機關與乙國立大學簽
訂委辦契約辦理科學技術研究計畫，依契約規定於 X1 年 9 月 15日簽約
時，預先撥付半數計畫款50 萬元。乙國立大學於X1 年 12 月 31日依約
就已執行部分，先行辦理核銷 35 萬元。該計畫於 X2 年 3 月 20 日完成
時，乙國立大學取得甲機關撥付之賸餘半數款項50 萬元，並完成計畫經
費之核銷。請以下表所列格式，列示在各交易事項發生時，除預算控制
類分錄外，甲機關應有之會計分錄。（25分）
（各項分錄之會計科目應以第四級科目名稱為準；若無分錄亦應註明
之，否則不予給分。）
